w("p3_26_bar_graph2.py", T("P3_BarGraph2","P3","Bar Graphs","Drawing bar charts", prob("Draw a bar graph for: Math=8, Sci=6, Eng=4") + "        for i,(name,val,c) in enumerate([('Math',8,TEAL),('Sci',6,BLUE),('Eng',4,ACCENT)]):\n            bar=Rectangle(width=1,height=val*0.3,color=c,fill_opacity=0.5)\n            bar.move_to(LEFT*2.5+RIGHT*i*2+DOWN*0.5+UP*val*0.15)\n            lbl=Text(name,font_size=20,color=c).next_to(bar,DOWN,buff=0.1)\n            vt=Text(str(val),font_size=20,color=c).next_to(bar,UP,buff=0.1)\n            self.play(GrowFromEdge(bar,DOWN),Write(lbl),Write(vt),run_time=0.5)\n" + ans("Math has the tallest bar!")))
