w("p4_15_factors.py", T("P4_Factors","P4","Factors","Numbers that divide evenly", prob("Find all factors of 12") + "        factors=[(1,12),(2,6),(3,4)]\n        for i,(a,b) in enumerate(factors):\n            t=Text(f'{a} x {b} = 12',font_size=26,color=TEAL).move_to(UP*0.5+DOWN*i*0.6)\n            self.play(Write(t),run_time=0.3)\n        fl=Text('Factors: 1,2,3,4,6,12',font_size=26,color=GOLD).move_to(DOWN*1.5)\n        self.play(Write(fl),run_time=0.4)\n" + ans("12 has 6 factors")))
