w("p4_17_tables_review.py", T("P4_TablesReview","P4","Times Tables Review","Quick recall", prob("Speed test!") + "        qs=[('6x7','42'),('8x9','72'),('7x4','28'),('9x6','54')]\n        for i,(q,a) in enumerate(qs):\n            y=UP*0.8+DOWN*i*0.6\n            self.play(Write(Text(q+'=?',font_size=28,color=WHITE_C).move_to(LEFT*2+y)),run_time=0.2)\n            self.wait(0.3)\n            self.play(Write(Text(a,font_size=28,color=GOLD).move_to(RIGHT*2+y)),run_time=0.2)\n" + ans("Practice makes perfect!")))


