w("p4_22_line_graph.py", T("P4_LineGraph","P4","Line Graphs","Trends over time", prob("Temperature over 5 days") + "        import numpy as np\n        axes=Axes(x_range=[0,5,1],y_range=[20,35,5],x_length=6,y_length=3,axis_config={'color':WHITE_C,'font_size':16}).move_to(DOWN*0.3)\n        self.play(Create(axes),run_time=0.5)\n        pts=[(1,25),(2,28),(3,30),(4,27),(5,32)]\n        dots=VGroup()\n        for x,y in pts:\n            d=Dot(axes.c2p(x,y),radius=0.08,color=GOLD)\n            dots.add(d)\n            self.play(GrowFromCenter(d),run_time=0.2)\n        lines=VGroup()\n        for i in range(len(pts)-1):\n            l=Line(axes.c2p(*pts[i]),axes.c2p(*pts[i+1]),color=TEAL,stroke_width=2)\n            lines.add(l)\n            self.play(Create(l),run_time=0.2)\n" + ans("Temperature went up and down!")))
w("p4_23_tables_data2.py", T("P4_TablesData2","P4","Two-Way Tables","Rows and columns", prob("Read the two-way table") + "        header=Text('     Boys  Girls',font_size=20,color=GOLD).move_to(UP*1.2)\n        self.play(Write(header),run_time=0.3)\n        for i,(act,b,g) in enumerate([('Soccer',8,5),('Swimming',6,9)]):\n            row=Text(f'{act}   {b}     {g}',font_size=20,color=WHITE_C).move_to(UP*0.5+DOWN*i*0.6)\n            self.play(Write(row),run_time=0.3)\n" + ans("Swimming: more girls. Soccer: more boys")))
