w("p4_34_angle_measure.py", T("P4_AngleMeasure","P4","Measuring Angles","Using a protractor", prob("Measure the angle") + "        import numpy as np\n        origin=LEFT*2+DOWN*0.3\n        r1=Line(origin,origin+RIGHT*2.5,color=WHITE_C,stroke_width=3)\n        r2=Line(origin,origin+2*np.array([np.cos(PI/3),np.sin(PI/3),0]),color=WHITE_C,stroke_width=3)\n        arc=Arc(radius=0.8,start_angle=0,angle=PI/3,color=GOLD,stroke_width=3).move_arc_center_to(origin)\n        lbl=Text('60 degrees',font_size=24,color=GOLD).move_to(origin+RIGHT*1.5+UP*0.8)\n        self.play(Create(r1),Create(r2),Create(arc),Write(lbl),run_time=0.8)\n" + ans("The angle is 60 degrees")))
