w("p4_37_bar_model_fraction.py", T("P4_BarModelFrac","P4","Bar Model with Fractions","Fraction of total", prob("3/5 of 40 = ?") + "        uw=1.2\n        bars=VGroup(*[Rectangle(width=uw,height=0.6,color=TEAL if i<3 else WHITE_C,fill_opacity=0.4 if i<3 else 0.1,stroke_width=2) for i in range(5)]).arrange(RIGHT,buff=0).move_to(UP*0.3)\n        self.play(LaggedStart(*[Create(b) for b in bars],lag_ratio=0.08),run_time=0.6)\n" + steps(["5 parts = 40","1 part = 8","3 parts = 24"]) + ans("3/5 of 40 = 24")))
