w("p4_39_negative_intro.py", T("P4_NegativeIntro","P4","Negative Numbers","Below zero", prob("Temperature: 3 degrees drops 5") + "        nl=NumberLine(x_range=[-5,5,1],length=10,include_numbers=True,font_size=18,color=WHITE_C).move_to(UP*0.5)\n        self.play(Create(nl),run_time=0.5)\n        d=Dot(nl.n2p(3),radius=0.12,color=TEAL)\n        self.play(GrowFromCenter(d),run_time=0.3)\n        for j in range(5):\n            arc=ArcBetweenPoints(nl.n2p(3-j)+UP*0.2,nl.n2p(2-j)+UP*0.2,angle=PI/3,color=ACCENT)\n            self.play(Create(arc),run_time=0.2)\n        self.play(GrowFromCenter(Dot(nl.n2p(-2),radius=0.12,color=ACCENT)),run_time=0.3)\n" + ans("3 - 5 = -2 degrees")))
w("p4_40_coordinates.py", T("P4_Coordinates","P4","Coordinates","Grid positions", prob("Plot point (3, 2)") + "        axes=Axes(x_range=[0,5,1],y_range=[0,5,1],x_length=5,y_length=5,axis_config={'color':WHITE_C,'font_size':16}).move_to(DOWN*0.2)\n        self.play(Create(axes),run_time=0.5)\n        d=Dot(axes.c2p(3,2),radius=0.12,color=GOLD)\n        lbl=Text('(3,2)',font_size=22,color=GOLD).next_to(d,UR,buff=0.1)\n        dl=DashedLine(axes.c2p(3,0),axes.c2p(3,2),color=TEAL)\n        dr=DashedLine(axes.c2p(0,2),axes.c2p(3,2),color=ACCENT)\n        self.play(Create(dl),Create(dr),GrowFromCenter(d),Write(lbl),run_time=0.6)\n" + ans("Point (3,2): right 3, up 2")))


w("p4_41_square_numbers.py", T("P4_SquareNumbers","P4","Square Numbers","Perfect squares", prob("What are square numbers?") + "        for i,n in enumerate([1,4,9,16,25]):\n            s=int(n**0.5)\n            grid=VGroup(*[Square(side_length=0.25,color=TEAL,fill_opacity=0.3,stroke_width=1) for _ in range(n)]).arrange_in_grid(rows=s,buff=0.03).move_to(LEFT*4+RIGHT*i*2+UP*0.3)\n            lbl=Text(f'{s}x{s}={n}',font_size=16,color=GOLD).next_to(grid,DOWN,buff=0.15)\n            self.play(FadeIn(grid),Write(lbl),run_time=0.4)\n" + ans("1, 4, 9, 16, 25 are square numbers")))
